public class CharFrequency {
    public static void countMetrics(String str) {
        int vowels = 0, consonants = 0, digits = 0, spaces = 0;
        str = str.toLowerCase();
        for (int i = 0; i < str.length(); i++) {
            char ch = str.charAt(i);
            if (ch >= 'a' && ch <= 'z') {
                if (ch == 'a' || ch == 'e' || ch == 'i' || ch == 'o' || ch == 'u') vowels++;
                else consonants++;
            } else if (ch >= '0' && ch <= '9') {
                digits++;
            } else if (ch == ' ') {
                spaces++;
            }
        }
        System.out.println("Vowels: " + vowels + ", Consonants: " + consonants);
        System.out.println("Digits: " + digits + ", Spaces: " + spaces);
    }

    public static int[] getFrequencies(String str) {
        int[] freq = new int[256];
        for (int i = 0; i < str.length(); i++) {
            freq[str.charAt(i)]++;
        }
        return freq;
    }

    public static void main(String[] args) {
        String test = "Java Master 123";
        countMetrics(test);
    }
}

public class ReverseString {
    public static String reverseRecursive(String str) {
        if (str == null || str.length() <= 1) return str;
        return reverseRecursive(str.substring(1)) + str.charAt(0);
    }

    public static String reverseWordsOrder(String s) {
        String[] words = s.trim().split("\\s+");
        StringBuilder sb = new StringBuilder();
        for (int i = words.length - 1; i >= 0; i--) {
            sb.append(words[i]);
            if (i > 0) sb.append(" ");
        }
        return sb.toString();
    }

