public class PalindromeProblems {
    public static boolean isPalindrome(String s) {
        int left = 0, right = s.length() - 1;
        while (left < right) {
            while (left < right && !Character.isLetterOrDigit(s.charAt(left))) left++;
            while (left < right && !Character.isLetterOrDigit(s.charAt(right))) right--;
            if (Character.toLowerCase(s.charAt(left)) != Character.toLowerCase(s.charAt(right))) {
                return false;
            }
            left++; right--;
        }
        return true;
    }

    private static int start, maxLen;
    public static String longestPalindrome(String s) {
        if (s.length() < 2) return s;
        start = 0; maxLen = 0;
        for (int i = 0; i < s.length(); i++) {
            expand(s, i, i);     // Odd length
            expand(s, i, i + 1); // Even length
        }
        return s.substring(start, start + maxLen);
    }

    private static void expand(String s, int l, int r) {
        while (l >= 0 && r < s.length() && s.charAt(l) == s.charAt(r)) {
            l--; r++;
        }
        int len = r - l - 1;
        if (len > maxLen) {
            start = l + 1;
            maxLen = len;
        }
    }

    public static void main(String[] args) {
        System.out.println("Is Palindrome: " + isPalindrome("A man, a plan, a canal: Panama"));
        System.out.println("Longest Palindromic Substring: " + longestPalindrome("babad"));
    }
}

