public class LexicographicalProblems {
    public static int compareManual(String s1, String s2) {
        int lim = Math.min(s1.length(), s2.length());
        for (int i = 0; i < lim; i++) {
            if (s1.charAt(i) != s2.charAt(i)) {
                return s1.charAt(i) - s2.charAt(i);
            }
        }
