public class StackStrings {
    public static String decodeString(String s) {
        Stack<Integer> countStack = new Stack<>();
        Stack<StringBuilder> resStack = new Stack<>();
        StringBuilder curr = new StringBuilder();
        int k = 0;
        for (char ch : s.toCharArray()) {
            if (Character.isDigit(ch)) {
                k = k * 10 + (ch - '0');
            } else if (ch == '[') {
                countStack.push(k);
                resStack.push(curr);
                curr = new StringBuilder();
                k = 0;
            } else if (ch == ']') {
                StringBuilder decoded = resStack.pop();
                int repeat = countStack.pop();
                for (int i = 0; i < repeat; i++) decoded.append(curr);
                curr = decoded;
            } else {
                curr.append(ch);
            }
        }
        return curr.toString();
    }

    public static void main(String[] args) {
        System.out.println("Decoded String: " + decodeString("3[a]2[bc]"));
    }
}

public class AdvancedStrings {
    public static String multiply(String num1, String num2) {
        if ("0".equals(num1) || "0".equals(num2)) return "0";
        int m = num1.length(), n = num2.length();
        int[] pos = new int[m + n];
        for (int i = m - 1; i >= 0; i--) {
            for (int j = n - 1; j >= 0; j--) {
                int mul = (num1.charAt(i) - '0') * (num2.charAt(j) - '0');
                int sum = mul + pos[i + j + 1];
                pos[i + j + 1] = sum % 10;
                pos[i + j] += sum / 10;
            }
        }
        StringBuilder sb = new StringBuilder();
        for (int p : pos) if (!(sb.length() == 0 && p == 0)) sb.append(p);
        return sb.toString();
    }

    public static void main(String[] args) {
        System.out.println("Multiplied: " + multiply("123", "456"));
    }
}

