public class HeapArrayProblems {
    static class QueueNode implements Comparable<QueueNode> {
        int value, arrayIndex, elementIndex;
        QueueNode(int value, int arrIdx, int elIdx) {
            this.value = value;
            this.arrayIndex = arrIdx;
            this.elementIndex = elIdx;
        }
        public int compareTo(QueueNode other) {
            return Integer.compare(this.value, other.value);
        }
    }

    public static List<Integer> mergeKSortedArrays(int[][] arrays) {
        List<Integer> res = new ArrayList<>();
        PriorityQueue<QueueNode> minHeap = new PriorityQueue<>();
        for (int i = 0; i < arrays.length; i++) {
            if (arrays[i].length > 0) {
                minHeap.add(new QueueNode(arrays[i][0], i, 0));
            }
        }
        while (!minHeap.isEmpty()) {
            QueueNode curr = minHeap.poll();
            res.add(curr.value);
            if (curr.elementIndex + 1 < arrays[curr.arrayIndex].length) {
                minHeap.add(new QueueNode(
                    arrays[curr.arrayIndex][curr.elementIndex + 1],
                    curr.arrayIndex,
                    curr.elementIndex + 1
                ));
            }
        }
        return res;
    }

    public static void main(String[] args) {
        int[][] arrays = {{1, 4, 7}, {2, 5, 8}, {3, 6, 9}};
