            this.data = val;
            this.next = null;
        }
    }

    public static boolean hasCycle(Node head) {
        if (head == null) return false;
        Node slow = head;
        Node fast = head;
        while (fast != null && fast.next != null) {
            slow = slow.next;
            fast = fast.next.next;
            if (slow == fast) {
                return true; // Loop detected
            }
        }
        return false;
    }

    public static void main(String[] args) {
        Node head = new Node(1);
        head.next = new Node(2);
        Node loopNode = new Node(3);
        head.next.next = loopNode;
        loopNode.next = new Node(4);
        loopNode.next.next = loopNode; // Creates a cycle pointing back to node 3

        System.out.println("Has Cycle: " + hasCycle(head));
    }
}

public class NumberReversal {
    public static int reverse(int num) {
        int rev = 0;
        while (num > 0) {
            int rem = num % 10;
            rev = (rev * 10) + rem;
            num /= 10;
        }
        return rev;
    }

    public static void main(String[] args) {
        int number = 12345;
        int reversed = reverse(number);
        System.out.println("Original: " + number);
        System.out.println("Reversed: " + reversed);
    }
}

public class PalindromeNumber {
    public static boolean isPalindrome(int num) {
        int temp = num;
        int rev = 0;
        while (num > 0) {
            int rem = num % 10;
            rev = (rev * 10) + rem;
            num /= 10;
        }
        return temp == rev;
    }

    public static void main(String[] args) {
        int val = 121;
        System.out.println(val + " is Palindrome: " + isPalindrome(val));
    }
}

public class ArmstrongNumber {
    public static boolean isArmstrong(int num) {
        int temp = num;
        int sum = 0;
        while (num > 0) {
            int rem = num % 10;
            sum += (rem * rem * rem);
            num /= 10;
        }
        return temp == sum;
    }

    public static void main(String[] args) {
        int val = 153;
        System.out.println(val + " is Armstrong: " + isArmstrong(val));
    }
}

public class PrimeChecker {
    public static boolean isPrime(int num) {
        if (num <= 1) return false;
        for (int i = 2; i * i <= num; i++) {
            if (num % i == 0) {
                return false;
            }
        }
        return true;
    }

    public static void main(String[] args) {
        int val = 13;
        System.out.println(val + " is Prime: " + isPrime(val));
    }
}

public class SwapNumbers {
    public static void main(String[] args) {
        int a = 10;
        int b = 20;
        System.out.println("Before Swap - a: " + a + ", b: " + b);

        a = a + b; // a becomes 30
        b = a - b; // b becomes 10
        a = a - b; // a becomes 20

        System.out.println("After Swap - a: " + a + ", b: " + b);
    }
}

import java.util.Arrays;

public class BubbleSort {
    public static void sort(int[] arr) {
        int n = arr.length;
        for (int i = 0; i < n - 1; i++) {
            for (int j = 0; j < n - i - 1; j++) {
                if (arr[j] > arr[j + 1]) {
                    int temp = arr[j];
                    arr[j] = arr[j + 1];
                    arr[j + 1] = temp;
                }
            }
        }
    }

    public static void main(String[] args) {
        int[] nums = {22, 5, 6, 88, 9};
        sort(nums);
        System.out.println("Sorted: " + Arrays.toString(nums));
    }
}
